const teamMap = {
  "Digital": { id: 45379727, branch: "main" },
  "Helios": { id: 71456629, branch: "main" },
  "Retail": { id: 45383610, branch: "main" },
  "Commerce": { id: 45379518, branch: "main" },
  "Clusters": { id: 45379816, branch: "main" },
  "Tooling": { id: 45950137, branch: "master" }
};

const team = $input.item.json.team;
const projectInfo = teamMap[team] || { id: 0, branch: "main" };
const jiraKey = $input.item.json.jira_key.toLowerCase();
const newBranch = `feat/infra-${jiraKey}`;

return [{ json: { ...$input.item.json, project_id: projectInfo.id, target_branch: projectInfo.branch, new_branch_name: newBranch } }];

const vars = $node["Set Variables"].json;
const proj = $node["Map Project ID"].json;
const body = vars.raw_body || {};
const safeName = (body.bucket_name || '').replace(/[^a-zA-Z0-9-_]/g, '');
const envs = JSON.stringify(body.target_environments || []);

const template = `##-----------S3 Bucket-------##
resource "aws_s3_bucket" "${safeName}" {
  count  = contains(${envs}, var.environment) ? 1 : 0
  bucket = "dh-${"\\" + "$"}{var.environment}-${body.bucket_name}"
  tags = {
    Environment = var.environment
    Purpose     = "${body.bucket_name}"
  }
}

resource "aws_s3_bucket_public_access_block" "${safeName}" {
  count                   = contains(${envs}, var.environment) ? 1 : 0
  bucket                  = aws_s3_bucket.${safeName}[0].id
  block_public_acls       = true
  ignore_public_acls      = true
  block_public_policy     = true
  restrict_public_buckets = true
}
`;

return [{ json: { ...vars, ...proj, tf_content: template, file_path: `iac/storage/${body.bucket_name}.tf` } }];

const vars = $node["Set Variables"].json;
const proj = $node["Map Project ID"].json;
const body = vars.raw_body || {};
const safeName = (body.identifier || '').replace(/[^a-zA-Z0-9-_]/g, '');
const sgName = safeName.replace(/-/g, '_');
const envs = JSON.stringify(body.target_environments || []);

const template = `##-----------Security Group-------##
resource "aws_security_group" "db_${sgName}" {
  count       = contains(${envs}, var.environment) ? 1 : 0
  description = "${body.identifier} RDS Access"
  vpc_id      = var.vpc_id
  ingress {
    protocol    = "tcp"
    from_port   = 5432
    to_port     = 5432
    cidr_blocks = concat(var.eks_vpc_private_subnet_cidrs, var.new_vpn_route, var.oms_general_vpc_private_subnet_cidrs)
  }
}

##-----------RDS-------##
module "${sgName}_rds_postgres" {
  source = "git::https://gitlab.com/iskaypetcom/digital/platform-engineering/aws/terraform-modules/rds-module.git?ref=main"

  count = contains(${envs}, var.environment) ? 1 : 0

  identifier           = "${safeName}-rds-postgres"
  db_name              = "${(body.db_name || '').replace(/[^a-zA-Z0-9]/g, '')}"
  username             = "${(body.db_name || '').replace(/[^a-zA-Z0-9]/g, '')}adm"
  environment          = var.environment
  size                 = "${body.size || 'small'}"

  vpc_security_group_ids = [aws_security_group.db_${sgName}[0].id]
  subnet_ids             = var.oms_pvt_subnet
  db_subnet_group_name   = "${safeName}-rds"

  tags = {
    domain = "${safeName}"
  }
}
`;

return [{ json: { ...vars, ...proj, tf_content: template, file_path: `iac/databases/${body.identifier}.tf` } }];

const vars = $node["Set Variables"].json;
