const resource = $node["Set Variables"].json.resource_name;
const type = $node["Set Variables"].json.resource_type.toUpperCase();
const mrUrl = $input.item.json.web_url;
const userName = $node["Set Variables"].json.requestor_email;
const ticket = $node["Set Variables"].json.jira_key;
const approvedBy = $node["Webhook"].json.body.approved_by_name || 'N/A';
const approvedByEmail = $node["Webhook"].json.body.approved_by_email || '';
const costSpecs = $node["Webhook"].json.body.cost_specs || '';
const costEst = $node["Webhook"].json.body.estimated_cost_monthly;
const costLine = costEst > 0 ? '~$' + costEst + '/mes' : 'Sin coste directo';
const envs = JSON.stringify($node["Webhook"].json.body.target_environments || []);

const card = {
  type: 'message',
  attachments: [
    {
      contentType: 'application/vnd.microsoft.card.adaptive',
      content: {
        type: 'AdaptiveCard',
        version: '1.4',
        msteams: { width: 'Full' },
        body: [
          {
            type: 'Container',
            items: [
              { type: 'TextBlock', text: 'Solicitud de Infraestructura', weight: 'Bolder', size: 'Medium', color: 'Good' },
              { type: 'TextBlock', text: resource, weight: 'Bolder', size: 'ExtraLarge', spacing: 'None' },
              {
                type: 'FactSet',
                facts: [
                  { title: 'Tipo:', value: type },
                  { title: 'Specs:', value: costSpecs || type },
                  { title: 'Entornos:', value: envs },
                  { title: 'Coste:', value: costLine },
                  { title: 'Solicitante:', value: userName },
                  { title: 'Aprobado por:', value: approvedBy + ' (' + approvedByEmail + ')' },
                  { title: 'Jira:', value: '[' + ticket + '](https://iskaypet.atlassian.net/browse/' + ticket + ')' }
                ]
              }
            ]
          }
        ],
        actions: [
          { type: 'Action.OpenUrl', title: 'Ver Merge Request', url: mrUrl },
          { type: 'Action.OpenUrl', title: 'Ver Ticket en Jira', url: 'https://iskaypet.atlassian.net/browse/' + ticket }
        ]
      }
    }
  ]
};

return [{ json: { teamsBody: card } }];
